noncompliant:
public class Parent
{
  public Parent()
  {
    DoSomething();  // Noncompliant: calling virtual method
  }

  public virtual void DoSomething() // can be overridden
  {
    // ...
  }
}

public class Child : Parent
{
  private string foo;

  public Child(string foo) // leads to call DoSomething() in Parent constructor which triggers a NullReferenceException as foo has not yet been initialized
  {
    this.foo = foo;
  }

  public override void DoSomething()
  {
    Console.WriteLine(this.foo.Length);
  }
}

compliant:
public class Parent
{
  public Parent()
  {
    DoSomething();  // Compliant: calling sealed/private/static method
  }

  private void DoSomething() // cannot be overridden
  {
    // ...
  }
}

public class AlternativeParent
{
  public AlternativeParent()
  {
    Initialize();
  }

  public sealed void Initialize() // Compliant: sealed method cannot be overridden
  {
    // ...
  }
}
